import{_ as t}from"./chunks/2025-03-10_20-17-27.D78HaHS0.js";import{_ as a,c as o,o as i,ag as n}from"./chunks/framework.By5zrZ8k.js";const r="/Innovation-Labs/neocore/2025-12-04_13-12-25.gif",s="/Innovation-Labs/neocore/2025-12-04_14-24-13.gif",c="/Innovation-Labs/neocore/NetApp%20Neo%20-%20How%20to%20delete%20a%20connector.gif",v=JSON.parse('{"title":"Microsoft 365 Copilot","description":"","frontmatter":{},"headers":[],"relativePath":"projects/mlai/neo/core/m-m365-copilot.md","filePath":"projects/mlai/neo/core/m-m365-copilot.md","lastUpdated":1773130255000}'),l={name:"projects/mlai/neo/core/m-m365-copilot.md"};function h(p,e,d,u,g,m){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="microsoft-365-copilot" tabindex="-1">Microsoft 365 Copilot <a class="header-anchor" href="#microsoft-365-copilot" aria-label="Permalink to &quot;Microsoft 365 Copilot&quot;">​</a></h1><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>In Neo v4, Microsoft Graph integration is handled by the <strong>Worker service</strong>, which manages Graph connection creation, item uploads, ACL synchronization, and cleanup. The API service provides endpoints for configuring Graph credentials and monitoring sync status.</p><h3 id="configuring-graph-credentials" tabindex="-1">Configuring Graph Credentials <a class="header-anchor" href="#configuring-graph-credentials" aria-label="Permalink to &quot;Configuring Graph Credentials&quot;">​</a></h3><p>Graph credentials can be configured in two ways:</p><ol><li><p><strong>Environment variables</strong>: Set <code>MS_GRAPH_CLIENT_ID</code>, <code>MS_GRAPH_CLIENT_SECRET</code>, and <code>MS_GRAPH_TENANT_ID</code> in the Worker and API service environment.</p></li><li><p><strong>Setup API</strong>: Configure credentials at runtime via:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/v1/setup/graph</span></span></code></pre></div><p>This is useful for initial setup or rotating credentials without restarting services.</p></li></ol><h3 id="register-neo-as-a-connector-in-azure-entra" tabindex="-1">Register Neo as a connector in Azure Entra <a class="header-anchor" href="#register-neo-as-a-connector-in-azure-entra" aria-label="Permalink to &quot;Register Neo as a connector in Azure Entra&quot;">​</a></h3><p>In order for Neo to be able to securely communicate with M365 Copilot.</p><p><img src="'+t+'" alt="Select App Registration in the Add menu in Microsoft Azure Entra"></p><ol><li>Navigate to the Azure Entra portal and select &quot;Add&quot; and select the &quot;App Registration&quot; option.</li><li>Fill in the required fields and click &quot;Register&quot;. (No Redirect URI is required)</li><li>Copy the Application (client) ID and Directory (tenant) ID from the Overview page.</li><li>Navigate to the &quot;API permissions&quot; page and select &quot;Add a permission&quot;.</li><li>Select &quot;Microsoft Graph&quot; and then &quot;Application permissions&quot;.</li><li>Search for &quot;ExternalConnection.ReadWrite.OwnedBy&quot; and select the checkbox.</li><li>Search for &quot;ExternalItem.ReadWrite.OwnedBy&quot; and select the checkbox.</li><li>Search for &quot;User.Read&quot; and select the checkbox.</li><li>Search for &quot;User.Read.All&quot; and select the checkbox.</li><li>Search for &quot;Group.Read.All&quot; and select the checkbox</li><li>Click &quot;Add permissions&quot;.</li><li>Click &quot;Graph admin consent for (tenant)&quot; and click &quot;Yes&quot;.</li><li>Navigate to the &quot;Certificates &amp; secrets&quot; page and click &quot;New client secret&quot;.</li><li>Fill in the required fields and click &quot;Add&quot;.</li><li>Copy the value of the client secret.</li></ol><p>You have successfully registered Neo as a connector in Azure ENTRA. You will need the <strong>Application ID</strong>, <strong>Directory ID</strong>, and <strong>Client Secret</strong> for the next steps.</p><h2 id="graph-sync-monitoring" tabindex="-1">Graph Sync Monitoring <a class="header-anchor" href="#graph-sync-monitoring" aria-label="Permalink to &quot;Graph Sync Monitoring&quot;">​</a></h2><p>Neo provides API endpoints for monitoring and managing the Graph sync lifecycle for each share.</p><h3 id="check-sync-status" tabindex="-1">Check sync status <a class="header-anchor" href="#check-sync-status" aria-label="Permalink to &quot;Check sync status&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /shares/{share_id}/graph/status</span></span></code></pre></div><p>Returns the current Graph sync state for a share, including connection status, items uploaded, items pending, and any errors.</p><h3 id="backfill-items-to-graph" tabindex="-1">Backfill items to Graph <a class="header-anchor" href="#backfill-items-to-graph" aria-label="Permalink to &quot;Backfill items to Graph&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /shares/{share_id}/graph/backfill</span></span></code></pre></div><p>Triggers a backfill operation to upload any items that have been extracted but not yet synced to Microsoft Graph. Useful after initial setup or after resolving Graph connectivity issues.</p><h3 id="clean-up-graph-items" tabindex="-1">Clean up Graph items <a class="header-anchor" href="#clean-up-graph-items" aria-label="Permalink to &quot;Clean up Graph items&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /shares/{share_id}/graph/cleanup</span></span></code></pre></div><p>Removes items from the Microsoft Graph connection that no longer exist in the source share. This is automatically performed during crawl operations but can be triggered manually.</p><h3 id="retry-failed-uploads" tabindex="-1">Retry failed uploads <a class="header-anchor" href="#retry-failed-uploads" aria-label="Permalink to &quot;Retry failed uploads&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /shares/{share_id}/graph/retry-failed</span></span></code></pre></div><p>Retries all items that previously failed to upload to Microsoft Graph. Failed items are tracked in the database with error details for diagnostics.</p><h2 id="managing-the-connector-in-m365-admin-centre" tabindex="-1">Managing the connector in M365 Admin Centre <a class="header-anchor" href="#managing-the-connector-in-m365-admin-centre" aria-label="Permalink to &quot;Managing the connector in M365 Admin Centre&quot;">​</a></h2><p>Connectors can be managed via the M365 Admin Centre. This includes viewing connector status, managing data sources, and monitoring ingestion progress.</p><ol><li>Navigate to the Microsoft 365 Admin Centre.</li><li>Select &quot;Settings&quot; and then &quot;Microsoft 365 Copilot&quot;.</li><li>Select &quot;Connectors&quot; from the left-hand menu.</li><li>Here you can view all registered connectors, their status, and manage their settings.</li></ol><p><a href="https://admin.cloud.microsoft/?source=applauncher#/copilot/connectors" target="_blank" rel="noreferrer">Microsoft 365 Admin Centre: Copilot Connectors</a></p><h2 id="check-item-level-permissions" tabindex="-1">Check item level permissions <a class="header-anchor" href="#check-item-level-permissions" aria-label="Permalink to &quot;Check item level permissions&quot;">​</a></h2><p>You can validate the item level permissions that the connector has in M365 via the Index Browser within the M365 Admin Centre as shown below:</p><p><img src="'+r+'" alt="M365 Admin Centre Index Browser showing item level permissions for the NetApp Neo connector"></p><h2 id="securing-access-to-results" tabindex="-1">Securing access to results <a class="header-anchor" href="#securing-access-to-results" aria-label="Permalink to &quot;Securing access to results&quot;">​</a></h2><p>You can control access to the ingested data via Microsoft 365 Copilot by configuring the appropriate permissions in M365. This includes setting up role-based access control (RBAC) and ensuring that only authorized users can access the data ingested by the connector.</p><p><img src="'+s+'" alt="M365 Admin Centre showing how to manage access to connector results"></p><h2 id="removing-a-connector" tabindex="-1">Removing a connector <a class="header-anchor" href="#removing-a-connector" aria-label="Permalink to &quot;Removing a connector&quot;">​</a></h2><p>You can easily remove a connector and all of its indexed content from Microsoft 365 Copilot via the M365 Admin Centre as shown below:</p><p><img src="'+c+'" alt="M365 Admin Centre showing how to remove a connector and all indexed content"></p>',38)])])}const q=a(l,[["render",h]]);export{v as __pageData,q as default};
